import React from 'react'
import styled from 'styled-components'

const CheckboxWrapper = styled.div `
display:flex;
align-items:center;
margin:4px 0;
`

const DepartmentTitle = styled.span `
font-size:0.8rem;
`

const Check = styled.input `
text-align:center;
`


export default function Checkbox ({foreignKey, handleCheckboxChange, value}) {
	const handleChecked = target => {
		handleCheckboxChange(target)
	}

	console.log(foreignKey)
	return (
			<label><CheckboxWrapper><Check type='checkbox'value={value.name} onChange={e => handleChecked(e)} foreignKey={foreignKey}/><DepartmentTitle>{value.name}</DepartmentTitle></CheckboxWrapper></label>

	)
}
